import java.io.File;
import java.io.IOException;

/**
 * Service class for validating and loading XML configuration files.
 */
public class ConfigService {

    /**
     * Validates and loads an XML configuration file into a DOM Document.
     *
     * @param configPath the path to the XML configuration file
     * @return the parsed DOM Document
     * @throws IllegalArgumentException if configPath is null or empty
     * @throws IOException              if the file does not exist or cannot be read
     * @throws SAXException             if the XML is malformed or validation fails
     */
    public Document loadConfig(String configPath) throws IOException, SAXException {
        // 1. Validate input parameters
        if (configPath == null || configPath.trim().isEmpty()) {
            throw new IllegalArgumentException("Configuration path cannot be null or empty.");
        }

        File configFile = new File(configPath);
        if (!configFile.exists()) {
            throw new IOException("Configuration file not found at: " + configPath);
        }

        // 2. Parse the XML into a DOM Document using a securely configured factory
        DocumentBuilderFactory documentBuilderFactory = DocumentBuilderFactory.newInstance();
        try {
            documentBuilderFactory.setFeature(XMLConstants.FEATURE_SECURE_PROCESSING, true);
            documentBuilderFactory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
            documentBuilderFactory.setFeature("http://xml.org/sax/features/external-general-entities", false);
            documentBuilderFactory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
            documentBuilderFactory.setXIncludeAware(false);
            documentBuilderFactory.setExpandEntityReferences(false);
        } catch (ParserConfigurationException e) {
            throw new RuntimeException("Failed to configure DocumentBuilderFactory securely: " + e.getMessage(), e);
        }

        DocumentBuilder documentBuilder;
        try {
            documentBuilder = documentBuilderFactory.newDocumentBuilder();
        } catch (ParserConfigurationException e) {
            throw new RuntimeException("Failed to create DocumentBuilder: " + e.getMessage(), e);
        }

        Document document = documentBuilder.parse(configFile);
        document.getDocumentElement().normalize();

        return document;
    }
}

